import type { ContentItem } from '~/types/content';

export function useContentMeta(item: ContentItem) {
  const date = computed(() => {
    const d = item.publishedAt || item.createdAt;
    if (!d) return '';
    return new Date(d).toLocaleDateString('ru-RU', {
      day: 'numeric',
      month: 'long',
      year: 'numeric',
    });
  });

  const shortDate = computed(() => {
    const d = item.publishedAt || item.createdAt;
    if (!d) return '';
    return new Date(d).toLocaleDateString('ru-RU', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
    });
  });

  const category = computed(() => {
    return item.categories?.[0]?.name || '';
  });

  const categorySlug = computed(() => {
    return item.categories?.[0]?.slug || '';
  });

  const typeLabel = computed(() => {
    switch (item.type) {
      case 'article':
        return 'Статья';
      case 'news':
        return 'Новость';
      case 'video':
        return 'Видео';
      case 'gallery':
        return 'Галерея';
      default:
        return '';
    }
  });

  return { date, shortDate, category, categorySlug, typeLabel };
}
<script setup lang="ts">
import type { ContentItem } from '~/types/content';

const props = withDefaults(
  defineProps<{
    item: ContentItem;
    imageAspect?: 'square' | 'video';
    variant?: 'default' | 'compact';
  }>(),
  { imageAspect: 'square', variant: 'default' },
);

const coverSrc = computed(() => useMediaUrl(props.item.coverMedia?.path));
const { date, category } = useContentMeta(props.item);
const { user } = useAuth();
const canEdit = computed(() => ['admin', 'editor'].includes(user.value?.role || ''));

function editUrl(item: ContentItem) {
  return `/account?type=${item.type}&id=${item.id}`;
}

const link = computed(() => {
  switch (props.item.type) {
    case 'article':
      return `/articles/${props.item.slug}`;
    case 'news':
      return `/news/${props.item.slug}`;
    case 'video':
      return `/videos/${props.item.slug}`;
    case 'gallery':
      return `/gallery/${props.item.slug}`;
    default:
      return '/';
  }
});
</script>

<template>
  <div
    class="group relative min-w-0 overflow-hidden border border-foreground/10 bg-card"
    :class="variant === 'compact' ? 'flex h-[320px] flex-col' : 'block'"
  >
    <NuxtLink
      :to="link"
      class="block"
      :class="variant === 'compact' ? 'flex h-full flex-col' : ''"
    >
    <div
      class="relative w-full overflow-hidden bg-foreground/10"
      :class="{
        'aspect-square': imageAspect === 'square' && variant !== 'compact',
        'aspect-video': imageAspect === 'video' || variant === 'compact',
      }"
    >
      <NuxtImg
        v-if="item.coverMedia?.path"
        :src="coverSrc"
        :alt="item.coverMedia.altText || item.title"
        loading="lazy"
        decoding="async"
        class="h-full w-full object-cover transition duration-500 group-hover:scale-105"
      />
      <span
        v-if="item.materialLabel === 'exclusive'"
        class="absolute bottom-2 right-2 rounded bg-red-700 px-1.5 py-0.5 text-[10px] font-bold uppercase tracking-wide text-white"
      >
        Эксклюзив
      </span>
    </div>
    <div
      class="overflow-hidden"
      :class="variant === 'compact' ? 'flex flex-1 flex-col p-3' : 'p-4'"
    >
      <div class="mb-1.5 flex flex-wrap items-center gap-2 text-xs text-foreground/50">
        <span v-if="category">{{ category }}</span>
        <span v-if="date">{{ date }}</span>
      </div>
      <h3
        class="font-heading font-bold leading-snug group-hover:text-foreground"
        :class="variant === 'compact' ? 'break-words text-[17px] leading-snug line-clamp-3' : 'break-words text-lg'"
      >
        {{ item.title }}
      </h3>
      <p
        v-if="item.excerpt && variant !== 'compact'"
        class="mt-2 line-clamp-2 text-sm opacity-80"
      >
        {{ item.excerpt }}
      </p>
    </div>
    </NuxtLink>
    <NuxtLink
      v-if="canEdit"
      :to="editUrl(item)"
      class="absolute right-2 top-2 z-10 rounded bg-accent px-2 py-1 text-[10px] font-bold uppercase tracking-wide text-white shadow-sm hover:bg-accent/90"
    >
      Редактировать
    </NuxtLink>
  </div>
</template>
<script setup lang="ts">
import type { ContentItem } from '~/types/content';
import { sortBySidebarCategoryOrder, resolveSidebarCategoryLabel } from '~/utils/sidebar-categories';

const props = defineProps<{
  groups: { category: { id: string; name: string; slug: string }; items: ContentItem[] }[];
}>();

const orderedGroups = computed(() =>
  sortBySidebarCategoryOrder(props.groups).map((group) => ({
    ...group,
    category: {
      ...group.category,
      name: resolveSidebarCategoryLabel(group.category),
    },
  })),
);

function link(item: ContentItem) {
  switch (item.type) {
    case 'article':
      return `/articles/${item.slug}`;
    case 'news':
      return `/news/${item.slug}`;
    case 'video':
      return `/videos/${item.slug}`;
    case 'gallery':
      return `/gallery/${item.slug}`;
    default:
      return '/';
  }
}

function formatDayMonth(date?: string | null) {
  if (!date) return '';
  return new Date(date).toLocaleDateString('ru-RU', { day: '2-digit', month: '2-digit' });
}

function truncatedTitle(title: string, exclusive: boolean): string {
  const max = exclusive ? 40 : 200;
  if (title.length <= max) return title;
  return title.slice(0, max).trim().replace(/[\s.,!?;:]$/, '') + '…';
}
</script>

<template>
  <div class="border border-foreground/5 bg-card p-5 shadow-sm md:p-6">
    <div class="space-y-8">
      <div v-for="group in orderedGroups" :key="group.category.id">
        <NuxtLink
          :to="`/category/${group.category.slug}`"
          class="mb-3 block text-base font-bold text-accent hover:text-accent/80"
        >
          {{ group.category.name }}
        </NuxtLink>
        <ul class="space-y-3">
          <li v-for="item in group.items" :key="item.id">
            <NuxtLink :to="link(item)" class="group flex items-start gap-3">
              <span class="shrink-0 pt-0.5 text-sm font-bold text-accent">
                {{ formatDayMonth(item.publishedAt || item.createdAt) }}
              </span>
              <div class="min-w-0 flex-1">
                <p class="text-sm font-medium leading-snug text-foreground group-hover:text-foreground line-clamp-2">
                  {{ truncatedTitle(item.title, item.materialLabel === 'exclusive') }}
                  <span
                    v-if="item.materialLabel === 'exclusive'"
                    class="ml-1 inline-block whitespace-nowrap align-middle rounded bg-red-700 px-1.5 py-0.5 text-[10px] font-bold uppercase tracking-wide text-white"
                  >
                    Эксклюзив
                  </span>
                </p>
              </div>
            </NuxtLink>
          </li>
        </ul>
      </div>
    </div>
  </div>
</template>
